import { GoldRushClient } from "@covalenthq/client-sdk";

const client = new GoldRushClient(process.env.GOLDRUSH_API_KEY);

async function trackNFTRoyalties(chainName, creatorAddress) {
  const txns = await client.TransactionService.getTransactionsForAddressV3(
    chainName, creatorAddress
  );
  // Filter royalty-like incoming transfers from known NFT marketplaces
  const royalties = (txns.data?.items ?? []).filter(tx =>
    tx.to_address === creatorAddress && (tx.value_quote ?? 0) > 0
  );
  const totalEarned = royalties.reduce((s, tx) => s + (tx.value_quote ?? 0), 0);
  return { creatorAddress, totalEarned, royaltyPayments: royalties.length };
}
